1	import { randomUUID } from 'crypto';
2	
3	import { Redis } from 'ioredis';
4	import * as jwt from 'jsonwebtoken';
5	import Knex from 'knex';
6	
7	import { ISession } from '@modules/session/types/session.interface';
8	
9	const JWT_SECRET = 'test-jwt-secret-at-least-32-characters-long';
10	const SESSION_TTL = 30 * 24 * 60 * 60;
11	
12	export interface ITestUser {
13		_id: string;
14		email: string;
15		name: string | null;
16		avatar_url: string | null;
17	}
18	
19	export interface ITestSession {
20		userId: string;
21		sessionId: string;
22		refreshToken: string;
23	}
24	
25	export interface ITestAuthResult {
26		user: ITestUser;
27		accessToken: string;
28		session: ITestSession;
29	}
30	
31	export interface ITestAdminAuthResult extends ITestAuthResult {
32		companyId: string;
33	}
34	
35	export function createTestUser({ email }: { email: string }): ITestUser {
36		return {
37			_id: randomUUID(),
38			email,
39			name: 'Test User',
40			avatar_url: null,
41		};
42	}
43	
44	export async function insertUser({
45		knex,
46		user,
47	}: {
48		knex: Knex.Knex;
49		user: ITestUser;
50	}): Promise<ITestUser> {
51		await knex('users').insert({
52			_id: user._id,
53			email: user.email,
54			name: user.name,
55			avatar_url: user.avatar_url,
56			created_at: knex.fn.now(),
57			updated_at: knex.fn.now(),
58		});
59		return user;
60	}
61	
62	export async function insertCompany({
63		knex,
64		name,
65	}: {
66		knex: Knex.Knex;
67		name: string;
68	}): Promise<{ _id: string; name: string }> {
69		const _id = randomUUID();
70		await knex('companies').insert({
71			_id,
72			name,
73			created_at: knex.fn.now(),
74			updated_at: knex.fn.now(),
75		});
76		return { _id, name };
77	}
78	
79	export async function insertCompanyMember({
80		knex,
81		userId,
82		companyId,
83		role,
84	}: {
85		knex: Knex.Knex;
86		userId: string;
87		companyId: string;
88		role: 'admin' | 'member';
89	}): Promise<void> {
90		await knex('company_members').insert({
91			_id: randomUUID(),
92			user_id: userId,
93			company_id: companyId,
94			role,
95			created_at: knex.fn.now(),
96			updated_at: knex.fn.now(),
97		});
98	}
99	
100	export function createAccessToken({
101		userId,
102		sessionId,
103		role,
104		companyId,
105	}: {
106		userId: string;
107		sessionId: string;
108		role: 'admin' | 'member' | null;
109		companyId: string | null;
110	}): string {
111		return jwt.sign(
112			{ user_id: userId, session_id: sessionId, role, company_id: companyId },
113			JWT_SECRET,
114			{ expiresIn: 3600 },
115		);
116	}
117	
118	export async function createSession({
119		redis,
120		userId,
121		sessionId,
122		role,
123		companyId,
124	}: {
125		redis: Redis;
126		userId: string;
127		sessionId: string;
128		role: 'admin' | 'member' | null;
129		companyId: string | null;
130	}): Promise<string> {
131		const refreshToken = randomUUID();
132		const now = new Date().toISOString();
133	
134		const session: ISession = {
135			user_id: userId,
136			session_id: sessionId,
137			role,
138			company_id: companyId,
139			provider: 'github',
140			ip: '127.0.0.1',
141			user_agent: 'test-agent',
142			created_at: now,
143			last_active: now,
144		};
145	
146		const payload = { user_id: userId, session_id: sessionId };
147	
148		await redis
149			.multi()
150			.set(`session:${userId}:${sessionId}`, JSON.stringify(session), 'EX', SESSION_TTL)
151			.sadd(`sessions:${userId}`, sessionId)
152			.set(`refresh:${refreshToken}`, JSON.stringify(payload), 'EX', SESSION_TTL)
153			.exec();
154	
155		return refreshToken;
156	}
157	
158	export async function setupTestUser({
159		knex,
160		redis,
161		email,
162		role,
163		companyId,
164	}: {
165		knex: Knex.Knex;
166		redis: Redis;
167		email: string;
168		role: 'admin' | 'member' | null;
169		companyId: string | null;
170	}): Promise<ITestAuthResult> {
171		const user = createTestUser({ email });
172		await insertUser({ knex, user });
173	
174		const sessionId = randomUUID();
175		const refreshToken = await createSession({
176			redis,
177			userId: user._id,
178			sessionId,
179			role,
180			companyId,
181		});
182	
183		const accessToken = createAccessToken({
184			userId: user._id,
185			sessionId,
186			role,
187			companyId,
188		});
189	
190		return {
191			user,
192			accessToken,
193			session: { userId: user._id, sessionId, refreshToken },
194		};
195	}
196	
197	export async function cleanDatabase({ knex }: { knex: Knex.Knex }): Promise<void> {
198		await knex.raw(
199			'TRUNCATE TABLE invitations, oauth_accounts, company_members, companies, users CASCADE',
200		);
201	}
202	
203	export async function cleanRedis({ redis }: { redis: Redis }): Promise<void> {
204		await redis.flushdb();
205	}
